import { z } from "zod";

//#region src/ai/chat/models/providers.ts
const ProviderTypeSchema = z.enum([
	"openai",
	"anthropic",
	"google",
	"openai-compatible"
]);
const ProviderOpenAi = z.object({
	provider: z.literal("openai"),
	model: z.string()
});
const ProviderAnthropic = z.object({
	provider: z.literal("anthropic"),
	model: z.string()
});
const ProviderGoogle = z.object({
	provider: z.literal("google"),
	model: z.string()
});
const ProviderOpenAiCompatible = z.object({
	provider: z.literal("openai-compatible"),
	model: z.string()
});

//#endregion
export { ProviderAnthropic, ProviderGoogle, ProviderOpenAi, ProviderOpenAiCompatible, ProviderTypeSchema };